    10→// ReleasesStore defines the persistence operations for releases (read-only).
    11→type ReleasesStore interface {
    12→	ListAllReleases(ctx context.Context, page, perPage int) ([]models.Release, int, error)
    13→	ListReleasesBySource(ctx context.Context, sourceID string, page, perPage int) ([]models.Release, int, error)
    14→	ListReleasesByProject(ctx context.Context, projectID string, page, perPage int) ([]models.Release, int, error)
    15→	GetRelease(ctx context.Context, id string) (*models.Release, error)
    16→}
    17→
    18→// ReleasesHandler implements HTTP handlers for the /releases resource.
    19→type ReleasesHandler struct {
    20→	store ReleasesStore
    21→}
    22→
    23→// NewReleasesHandler returns a new ReleasesHandler.
    24→func NewReleasesHandler(store ReleasesStore) *ReleasesHandler {
    25→	return &ReleasesHandler{store: store}
    26→}
    27→
    28→// List handles GET /releases — returns all releases across all projects.
    29→func (h *ReleasesHandler) List(w http.ResponseWriter, r *http.Request) {
    30→	page, perPage := ParsePagination(r)
    31→	releases, total, err := h.store.ListAllReleases(r.Context(), page, perPage)
    32→	if err != nil {
    33→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
    34→		return
    35→	}
    36→	if releases == nil {
    37→		releases = []models.Release{}
    38→	}
    39→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    40→}
    41→
    42→// ListBySource handles GET /sources/{id}/releases — returns releases for a specific source.
    43→func (h *ReleasesHandler) ListBySource(w http.ResponseWriter, r *http.Request) {
    44→	sourceID := r.PathValue("id")
    45→	if sourceID == "" {
    46→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Source ID is required")
    47→		return
    48→	}
    49→	page, perPage := ParsePagination(r)
    50→	releases, total, err := h.store.ListReleasesBySource(r.Context(), sourceID, page, perPage)
    51→	if err != nil {
    52→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
    53→		return
    54→	}
    55→	if releases == nil {
    56→		releases = []models.Release{}
    57→	}
    58→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    59→}
    60→
    61→// ListByProject handles GET /projects/{projectId}/releases — returns releases for all sources in a project.
    62→func (h *ReleasesHandler) ListByProject(w http.ResponseWriter, r *http.Request) {
    63→	projectID := r.PathValue("projectId")
    64→	if projectID == "" {
    65→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    66→		return
    67→	}
    68→	page, perPage := ParsePagination(r)
    69→	releases, total, err := h.store.ListReleasesByProject(r.Context(), projectID, page, perPage)
    70→	if err != nil {
    71→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list releases")
    72→		return
    73→	}
    74→	if releases == nil {
    75→		releases = []models.Release{}
    76→	}
    77→	RespondList(w, r, http.StatusOK, releases, page, perPage, total)
    78→}
    79→
    80→// Get handles GET /releases/{id} — returns a single release.
    81→func (h *ReleasesHandler) Get(w http.ResponseWriter, r *http.Request) {
    82→	id := r.PathValue("id")
    83→	if id == "" {
    84→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Release ID is required")
    85→		return
    86→	}
    87→	rel, err := h.store.GetRelease(r.Context(), id)
    88→	if err != nil {
    89→		RespondError(w, r, http.StatusNotFound, "not_found", "Release not found")
    90→		return
    91→	}
    92→	RespondJSON(w, r, http.StatusOK, rel)
    93→}
